"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[1638],{1638:e=>{e.exports=JSON.parse('{"33":{"words":[{"spanish":"la persona que media en el conflicto","english":"the person who mediates the conflict"},{"spanish":"el argumento que convence","english":"the argument that persuades"},{"spanish":"la propuesta que parece viable","english":"the proposal that seems workable"},{"spanish":"quien aporta pruebas s\xf3lidas","english":"whoever provides solid evidence"},{"spanish":"quienes discrepan con respeto","english":"those who disagree respectfully"},{"spanish":"el informe en el cual se analizan los datos","english":"the report in which the data are analyzed"},{"spanish":"la empresa para la cual trabajo","english":"the company I work for"},{"spanish":"el barrio donde crec\xed","english":"the neighborhood where I grew up"},{"spanish":"la raz\xf3n por la cual cambi\xf3 de opini\xf3n","english":"the reason why he or she changed their mind"},{"spanish":"el asunto del que hablamos","english":"the matter we are talking about"},{"spanish":"cuyo objetivo principal","english":"whose main objective"},{"spanish":"cuya conclusi\xf3n resulta pol\xe9mica","english":"whose conclusion turns out to be controversial"},{"spanish":"lo que me preocupa","english":"what worries me"},{"spanish":"lo cual demuestra","english":"which demonstrates"},{"spanish":"sin embargo","english":"however"},{"spanish":"no obstante","english":"nevertheless"},{"spanish":"por lo tanto","english":"therefore"},{"spanish":"en cambio","english":"by contrast"},{"spanish":"adem\xe1s","english":"moreover"},{"spanish":"aunque","english":"although"},{"spanish":"de hecho","english":"in fact"},{"spanish":"en cuanto a","english":"regarding"},{"spanish":"por un lado","english":"on the one hand"},{"spanish":"por otro lado","english":"on the other hand"},{"spanish":"a pesar de que","english":"even though"},{"spanish":"en la medida en que","english":"insofar as"},{"spanish":"siempre que","english":"provided that"},{"spanish":"dado que","english":"given that"},{"spanish":"seg\xfan el contexto","english":"depending on the context"},{"spanish":"desde una perspectiva amplia","english":"from a broad perspective"},{"spanish":"un matiz importante","english":"an important nuance"},{"spanish":"una objeci\xf3n razonable","english":"a reasonable objection"},{"spanish":"una postura matizada","english":"a nuanced position"},{"spanish":"una descripci\xf3n precisa","english":"a precise description"},{"spanish":"establecer un v\xednculo","english":"to establish a link"},{"spanish":"sostener una tesis","english":"to defend a thesis"},{"spanish":"refutar una afirmaci\xf3n","english":"to refute a claim"},{"spanish":"aportar un ejemplo","english":"to provide an example"},{"spanish":"hacer una distinci\xf3n","english":"to make a distinction"},{"spanish":"llegar a una conclusi\xf3n","english":"to reach a conclusion"},{"spanish":"un criterio relevante","english":"a relevant criterion"},{"spanish":"un detalle accesorio","english":"a secondary detail"}],"conversations":[{"id":1,"topic":"Elegir un piso con criterios distintos","dialog":[{"speaker":"Elena","spanish":"He visto un piso que est\xe1 junto al tranv\xeda y tiene un estudio donde podr\xeda trabajar; sin embargo, el edificio es m\xe1s ruidoso de lo que esperaba.","english":"I saw an apartment that is next to the tram and has a study where I could work; however, the building is noisier than I expected."},{"speaker":"Mart\xedn","spanish":"Yo preferir\xeda el apartamento del barrio hist\xf3rico, cuyo patio interior reduce el ruido; adem\xe1s, la due\xf1a con quien habl\xe9 aceptar\xeda un contrato largo.","english":"I would prefer the apartment in the historic neighborhood, whose inner courtyard reduces the noise; moreover, the owner I spoke with would accept a long contract."},{"speaker":"Elena","spanish":"Lo que me preocupa de ese barrio es que est\xe1 lejos de la oficina a la cual acaban de trasladarte, por lo cual pasar\xedas m\xe1s tiempo en el trayecto.","english":"What worries me about that neighborhood is that it is far from the office you have just been reassigned to, which means you would spend more time commuting."},{"speaker":"Mart\xedn","spanish":"Es cierto, aunque el piso que viste tambi\xe9n tiene gastos comunes muy altos, los cuales podr\xedan desequilibrar nuestro presupuesto en pocos meses.","english":"That is true, although the apartment you saw also has very high building fees, which could throw our budget off balance in a few months."},{"speaker":"Elena","spanish":"Entonces quiz\xe1 nos convenga el tercero, que no es tan bonito; en cambio, est\xe1 cerca de ambos trabajos y tiene una sala donde podr\xedamos recibir visitas.","english":"Then perhaps the third one suits us best, even if it is not as nice; by contrast, it is close to both jobs and has a living room where we could host visitors."},{"speaker":"Mart\xedn","spanish":"Me parece razonable, porque re\xfane lo esencial y, a pesar de que no tenga terraza, ofrece la estabilidad que buscamos ahora.","english":"That sounds reasonable to me, because it brings together the essentials and, even though it does not have a terrace, it offers the stability we are looking for right now."}],"questions":[{"question":"\xbfQu\xe9 valora especialmente Mart\xedn al considerar el apartamento del barrio hist\xf3rico?","options":["La terraza grande y la cocina nueva","El patio silencioso y la posibilidad de un contrato largo","La cercan\xeda inmediata al tranv\xeda","Los gastos comunes m\xe1s bajos"],"answer":"El patio silencioso y la posibilidad de un contrato largo","answerIndex":1},{"question":"\xbfPor qu\xe9 Elena duda del barrio hist\xf3rico a pesar de sus ventajas?","options":["Porque cree que la due\xf1a no es fiable","Porque el estudio es demasiado peque\xf1o","Porque queda lejos de la nueva oficina de Mart\xedn","Porque no admite visitas"],"answer":"Porque queda lejos de la nueva oficina de Mart\xedn","answerIndex":2},{"question":"\xbfA qu\xe9 conclusi\xf3n provisional llegan ambos?","options":["Que deber\xedan esperar varios meses antes de mudarse","Que el tercer piso equilibra mejor sus necesidades actuales","Que el piso junto al tranv\xeda es claramente superior","Que el barrio hist\xf3rico es la \xfanica opci\xf3n realista"],"answer":"Que el tercer piso equilibra mejor sus necesidades actuales","answerIndex":1}]},{"id":2,"topic":"Debate vecinal sobre un carril bici","dialog":[{"speaker":"Sof\xeda","spanish":"En cuanto a la avenida central, creo que necesita un carril bici que proteja a quienes van al mercado o a la escuela sin coche.","english":"Regarding the main avenue, I think it needs a bike lane that protects those who go to the market or school without a car."},{"speaker":"Diego","spanish":"Entiendo la idea; no obstante, los comerciantes con los cuales habl\xe9 temen perder espacios de carga, lo cual afectar\xeda las entregas de la ma\xf1ana.","english":"I understand the idea; nevertheless, the shopkeepers I spoke with fear losing loading spaces, which would affect morning deliveries."},{"speaker":"Sof\xeda","spanish":"Por un lado, esa preocupaci\xf3n es leg\xedtima; por otro lado, los datos del distrito vecino, donde redujeron el tr\xe1fico, muestran que aument\xf3 el paso de peatones.","english":"On the one hand, that concern is legitimate; on the other hand, data from the neighboring district, where traffic was reduced, show that foot traffic increased."},{"speaker":"Diego","spanish":"De hecho, si el ayuntamiento crea horarios de carga y descarga, las tiendas que dependen de camiones peque\xf1os podr\xedan adaptarse sin demasiado coste.","english":"In fact, if the city council creates loading and unloading schedules, the shops that depend on small trucks could adapt without too much cost."},{"speaker":"Sof\xeda","spanish":"Adem\xe1s, la propuesta incluye \xe1rboles y bancos, cuya presencia har\xeda la calle m\xe1s habitable para las personas mayores que ahora la evitan.","english":"Moreover, the proposal includes trees and benches, whose presence would make the street more livable for older people who currently avoid it."},{"speaker":"Diego","spanish":"Entonces apoyar\xe9 el plan siempre que se revise cada tres meses, porque un cambio de este tipo exige pruebas y ajustes, no solo entusiasmo.","english":"Then I will support the plan provided that it is reviewed every three months, because a change like this requires evidence and adjustments, not just enthusiasm."}],"questions":[{"question":"\xbfQu\xe9 condici\xf3n pone Diego para apoyar finalmente el plan?","options":["Que se eliminen todos los \xe1rboles del proyecto","Que se traslade el mercado a otra calle","Que el plan se revise peri\xf3dicamente con pruebas","Que solo se aplique los fines de semana"],"answer":"Que el plan se revise peri\xf3dicamente con pruebas","answerIndex":2},{"question":"\xbfQu\xe9 ejemplo utiliza Sof\xeda para defender que la medida podr\xeda funcionar?","options":["Una encuesta de turistas internacionales","Los datos de un distrito vecino que redujo el tr\xe1fico","Una promesa verbal del alcalde","La opini\xf3n de un solo comerciante"],"answer":"Los datos de un distrito vecino que redujo el tr\xe1fico","answerIndex":1},{"question":"\xbfQu\xe9 grupo menciona Sof\xeda como beneficiario adicional del proyecto?","options":["Las personas mayores que evitan la calle actual","Los conductores de larga distancia","Los estudiantes universitarios extranjeros","Los t\xe9cnicos de mantenimiento nocturno"],"answer":"Las personas mayores que evitan la calle actual","answerIndex":0}]},{"id":3,"topic":"Seminario sobre un ensayo argumentativo","dialog":[{"speaker":"Clara","spanish":"El ensayo que present\xf3 Nora me pareci\xf3 s\xf3lido, porque conecta testimonios y estad\xedsticas de una manera que pocas ponencias consiguen.","english":"The essay Nora presented seemed solid to me, because it connects testimonies and statistics in a way that few presentations manage."},{"speaker":"Javier","spanish":"Estoy de acuerdo en parte; sin embargo, la secci\xf3n en la cual analiza las causas econ\xf3micas simplifica un problema cuyo origen tambi\xe9n es cultural.","english":"I agree in part; however, the section in which she analyzes the economic causes oversimplifies a problem whose origin is also cultural."},{"speaker":"Clara","spanish":"Puede ser, aunque el objetivo del trabajo no era explicarlo todo, sino mostrar lo que ocurre cuando las pol\xedticas ignoran a las comunidades locales.","english":"That may be true, although the goal of the paper was not to explain everything, but to show what happens when policies ignore local communities."},{"speaker":"Javier","spanish":"Lo cual est\xe1 bien, pero yo habr\xeda incluido voces de quienes discrepan con la autora, ya que un argumento gana fuerza cuando reconoce sus l\xedmites.","english":"That is fair, but I would have included voices from those who disagree with the author, since an argument becomes stronger when it recognizes its limits."},{"speaker":"Clara","spanish":"De hecho, la profesora dijo que la revisi\xf3n final deb\xeda incorporar contraargumentos y ejemplos del municipio donde se aplic\xf3 el programa piloto.","english":"In fact, the professor said that the final revision had to include counterarguments and examples from the municipality where the pilot program was implemented."},{"speaker":"Javier","spanish":"Entonces el texto que entregar\xe1 la pr\xf3xima semana probablemente ser\xe1 m\xe1s persuasivo, porque partir\xe1 de una base buena y responder\xe1 a las objeciones relevantes.","english":"Then the text she will submit next week will probably be more persuasive, because it will build on a good foundation and respond to the relevant objections."}],"questions":[{"question":"\xbfCu\xe1l es la cr\xedtica principal que hace Javier al ensayo de Nora?","options":["Que no incluye ninguna estad\xedstica verificable","Que resume bien el tema, pero usa un lenguaje demasiado informal","Que simplifica demasiado un problema que tambi\xe9n tiene dimensi\xf3n cultural","Que ignora por completo las pol\xedticas locales"],"answer":"Que simplifica demasiado un problema que tambi\xe9n tiene dimensi\xf3n cultural","answerIndex":2},{"question":"\xbfPor qu\xe9 Clara sigue valorando el ensayo a pesar de esa cr\xedtica?","options":["Porque cree que el prop\xf3sito era evidenciar efectos de ciertas pol\xedticas, no abarcarlo todo","Porque la profesora prohibi\xf3 cualquier comentario cr\xedtico","Porque el municipio financi\xf3 la investigaci\xf3n","Porque el texto no necesita revisi\xf3n alguna"],"answer":"Porque cree que el prop\xf3sito era evidenciar efectos de ciertas pol\xedticas, no abarcarlo todo","answerIndex":0},{"question":"\xbfQu\xe9 espera la profesora de la versi\xf3n final?","options":["Que elimine los testimonios y deje solo n\xfameros","Que a\xf1ada contraargumentos y ejemplos del programa piloto","Que cambie el tema por completo","Que reduzca el texto a una sola p\xe1gina"],"answer":"Que a\xf1ada contraargumentos y ejemplos del programa piloto","answerIndex":1}]},{"id":4,"topic":"Elegir ponentes para una mesa redonda","dialog":[{"speaker":"Paula","spanish":"Tenemos dos ponentes posibles: la arquitecta que dirige el proyecto del puerto y el soci\xf3logo cuyas investigaciones sobre vivienda han abierto un debate muy necesario.","english":"We have two possible speakers: the architect who leads the port project and the sociologist whose research on housing has opened a very necessary debate."},{"speaker":"Andr\xe9s","spanish":"La arquitecta ser\xeda \xfatil si queremos explicar obras concretas; en cambio, el soci\xf3logo podr\xeda abordar el impacto humano, que es lo que m\xe1s interesa al vecindario.","english":"The architect would be useful if we want to explain specific construction projects; by contrast, the sociologist could address the human impact, which is what interests the neighborhood the most."},{"speaker":"Paula","spanish":"No obstante, la arquitecta trabaj\xf3 en un distrito donde lograron acuerdos entre residentes y empresas, lo cual se parece mucho a nuestra situaci\xf3n.","english":"Nevertheless, the architect worked in a district where they reached agreements between residents and companies, which closely resembles our situation."},{"speaker":"Andr\xe9s","spanish":"Es verdad, aunque el soci\xf3logo, con quien convers\xe9 ayer, aceptar\xeda responder preguntas dif\xedciles sobre alquileres, tema del cual nadie quiere hablar superficialmente.","english":"That is true, although the sociologist, whom I spoke with yesterday, would agree to answer difficult questions about rents, a topic nobody wants to discuss superficially."},{"speaker":"Paula","spanish":"Por lo tanto, quiz\xe1 convenga invitarlos a ambos y pedir que dialoguen entre s\xed, de modo que el p\xfablico vea perspectivas que no suelen encontrarse en el mismo foro.","english":"Therefore, it may be best to invite both and ask them to engage with each other, so that the audience sees perspectives that do not usually meet in the same forum."},{"speaker":"Andr\xe9s","spanish":"Me gusta esa f\xf3rmula, porque ofrece el contraste que busc\xe1bamos y evita la impresi\xf3n de que el centro cultural favorece una sola postura.","english":"I like that approach, because it offers the contrast we were looking for and avoids giving the impression that the cultural center favors only one position."}],"questions":[{"question":"\xbfPor qu\xe9 Paula propone invitar a los dos ponentes?","options":["Porque ninguno de los dos puede hablar solo durante una hora","Porque quiere mostrar perspectivas complementarias en un mismo foro","Porque el centro cultural debe gastar m\xe1s presupuesto","Porque ambos exigen viajar el mismo d\xeda"],"answer":"Porque quiere mostrar perspectivas complementarias en un mismo foro","answerIndex":1},{"question":"\xbfQu\xe9 tema considera Andr\xe9s especialmente delicado y dif\xedcil de tratar con superficialidad?","options":["La iluminaci\xf3n del puerto","Los alquileres","La historia del barrio","Los horarios del centro cultural"],"answer":"Los alquileres","answerIndex":1},{"question":"\xbfQu\xe9 experiencia de la arquitecta resulta relevante para Paula?","options":["Que public\xf3 un libro sobre turismo","Que trabaj\xf3 en un distrito similar donde hubo acuerdos entre residentes y empresas","Que ya particip\xf3 en una feria internacional","Que vive cerca del centro cultural"],"answer":"Que trabaj\xf3 en un distrito similar donde hubo acuerdos entre residentes y empresas","answerIndex":1}]}],"stories":[{"id":1,"title":"El informe que cambi\xf3 la reuni\xf3n","sentences":[{"spanish":"Durante semanas, Luc\xeda prepar\xf3 un informe en el cual comparaba tres planes de movilidad para un barrio que llevaba a\xf1os dividido.","english":"For weeks, Luc\xeda prepared a report in which she compared three mobility plans for a neighborhood that had been divided for years."},{"spanish":"Lo que m\xe1s le interesaba era mostrar c\xf3mo cada propuesta afectaba a las personas mayores, quienes rara vez asist\xedan a las reuniones t\xe9cnicas.","english":"What interested her most was showing how each proposal affected older residents, who rarely attended the technical meetings."},{"spanish":"Por un lado, el plan m\xe1s barato parec\xeda atractivo; por otro lado, eliminaba paradas de autob\xfas cuya ausencia aislar\xeda a muchos vecinos.","english":"On the one hand, the cheapest plan seemed appealing; on the other hand, it removed bus stops whose absence would isolate many neighbors."},{"spanish":"Sin embargo, otro plan que costaba un poco m\xe1s manten\xeda el transporte y a\xf1ad\xeda aceras seguras, lo cual cambi\xf3 por completo la discusi\xf3n.","english":"However, another plan that cost a little more preserved public transport and added safe sidewalks, which completely changed the discussion."},{"spanish":"A pesar de que algunos concejales quer\xedan votar de inmediato, Luc\xeda insisti\xf3 en que leyeran el apartado donde se resum\xedan los testimonios del barrio.","english":"Even though some council members wanted to vote immediately, Luc\xeda insisted that they read the section where the neighborhood testimonies were summarized."},{"spanish":"Por lo tanto, la reuni\xf3n que promet\xeda terminar en conflicto acab\xf3 con un acuerdo m\xe1s prudente y mejor argumentado.","english":"As a result, the meeting that seemed destined to end in conflict concluded with a more careful and better reasoned agreement."}]},{"id":2,"title":"La librera cuya memoria un\xeda historias","sentences":[{"spanish":"Carmen hered\xf3 una librer\xeda donde los clientes buscaban recomendaciones que no aparec\xedan en las listas de los m\xe1s vendidos.","english":"Carmen inherited a bookstore where customers looked for recommendations that did not appear on bestseller lists."},{"spanish":"Cada vez que alguien le ped\xeda una novela hist\xf3rica, ella recordaba autores cuyas voces permit\xedan entender \xe9pocas complejas sin convertirlas en caricatura.","english":"Whenever someone asked for a historical novel, she recalled authors whose voices made it possible to understand complex periods without turning them into caricatures."},{"spanish":"En cuanto a los lectores j\xf3venes, les ofrec\xeda ensayos breves que explicaban por qu\xe9 ciertas ideas siguen influyendo hoy.","english":"As for younger readers, she offered them short essays that explained why certain ideas still matter today."},{"spanish":"No obstante, nunca impon\xeda sus gustos, porque sab\xeda que la conversaci\xf3n que convence es la que parte de la curiosidad ajena.","english":"Nevertheless, she never imposed her tastes, because she knew that the conversation that persuades begins with another person\'s curiosity."},{"spanish":"De hecho, muchos clientes regresaban no solo por los libros, sino por la manera en que Carmen conectaba temas distintos y mostraba lo que cada obra pod\xeda revelar.","english":"In fact, many customers came back not only for the books, but for the way Carmen connected different themes and showed what each work could reveal."}]},{"id":3,"title":"El paseo donde surgi\xf3 la respuesta","sentences":[{"spanish":"Tom\xe1s sali\xf3 a caminar por el parque donde sol\xeda ordenar las ideas que no lograba escribir en su despacho.","english":"Tom\xe1s went for a walk through the park where he usually sorted out the ideas he could not write down in his office."},{"spanish":"Llevaba una carta cuya primera versi\xf3n sonaba demasiado dura para la colega con quien hab\xeda discutido la semana anterior.","english":"He was carrying a letter whose first draft sounded too harsh for the colleague he had argued with the week before."},{"spanish":"Aunque cre\xeda tener raz\xf3n, empez\xf3 a pensar en el comentario que ella hab\xeda hecho sobre los efectos del proyecto en barrios invisibles.","english":"Although he believed he was right, he began thinking about the remark she had made regarding the project\'s effects on overlooked neighborhoods."},{"spanish":"Lo cual lo llev\xf3 a revisar un dato que, de hecho, debilitaba una parte de su argumento.","english":"That led him to review a piece of data that, in fact, weakened part of his argument."},{"spanish":"Entonces reescribi\xf3 el mensaje de manera m\xe1s precisa y a\xf1adi\xf3 el reconocimiento que faltaba.","english":"He then rewrote the message more precisely and added the acknowledgment that had been missing."},{"spanish":"Gracias a esa pausa, la respuesta que envi\xf3 abri\xf3 una conversaci\xf3n productiva en lugar de cerrar el debate.","english":"Thanks to that pause, the reply he sent opened a productive conversation instead of shutting down the debate."}]}],"speaking":{"title":"Hablar con matices y conectar ideas","description":"Practica descripciones complejas, argumentos matizados y conectores avanzados.","questions_and_answers":[{"question":{"spanish":"Describe a una profesora que te haya influido y explica por qu\xe9.","english":"Describe a teacher who influenced you and explain why."},"answer":{"spanish":"La profesora que m\xe1s me influy\xf3 fue una mentora paciente que exig\xeda precisi\xf3n y, adem\xe1s, nos ense\xf1aba a defender nuestras ideas con respeto.","english":"The teacher who influenced me most was a patient mentor who demanded precision and also taught us to defend our ideas respectfully."}},{"question":{"spanish":"Explica qu\xe9 decisi\xf3n p\xfablica te preocupa y por qu\xe9.","english":"Explain which public decision worries you and why."},"answer":{"spanish":"Lo que m\xe1s me preocupa es la decisi\xf3n de cerrar bibliotecas de barrio, porque afecta a quienes dependen de esos espacios para estudiar y reunirse.","english":"What worries me most is the decision to close neighborhood libraries, because it affects those who rely on those spaces to study and gather."}},{"question":{"spanish":"Compara dos barrios donde podr\xedas vivir.","english":"Compare two neighborhoods where you could live."},"answer":{"spanish":"Por un lado, elegir\xeda un barrio tranquilo donde pueda caminar; por otro lado, tambi\xe9n valoro una zona c\xe9ntrica que me acerque al trabajo y a la vida cultural.","english":"On the one hand, I would choose a quiet neighborhood where I can walk; on the other hand, I also value a central area that brings me closer to work and cultural life."}},{"question":{"spanish":"Habla de una persona con quien te gusta debatir.","english":"Talk about a person you enjoy debating with."},"answer":{"spanish":"Me gusta debatir con un amigo que escucha con atenci\xf3n y que, aunque discrepa a menudo, siempre aporta ejemplos que enriquecen la conversaci\xf3n.","english":"I like debating with a friend who listens carefully and who, although he often disagrees, always provides examples that enrich the conversation."}},{"question":{"spanish":"Describe un libro cuyo final cambi\xf3 tu opini\xf3n.","english":"Describe a book whose ending changed your opinion."},"answer":{"spanish":"Le\xed una novela cuyo final me oblig\xf3 a reconsiderar al protagonista, porque lo que parec\xeda simple orgullo result\xf3 ser miedo y vulnerabilidad.","english":"I read a novel whose ending forced me to reconsider the protagonist, because what seemed like simple pride turned out to be fear and vulnerability."}},{"question":{"spanish":"Explica por qu\xe9 la evidencia fortalece un argumento.","english":"Explain why evidence strengthens an argument."},"answer":{"spanish":"La evidencia fortalece un argumento en la medida en que permite refutar objeciones y mostrar que la conclusi\xf3n no depende solo de opiniones.","english":"Evidence strengthens an argument insofar as it allows you to refute objections and show that the conclusion does not depend only on opinions."}},{"question":{"spanish":"Menciona un tema del que tus amigos suelen discrepar.","english":"Mention a topic your friends usually disagree about."},"answer":{"spanish":"El asunto del que m\xe1s discrepamos es el uso del coche en el centro, porque algunos priorizan la comodidad y otros, en cambio, la calidad del aire.","english":"The issue we disagree about most is car use downtown, because some prioritize convenience and others, by contrast, prioritize air quality."}},{"question":{"spanish":"Describe una ciudad donde el espacio p\xfablico funcione bien.","english":"Describe a city where public space works well."},"answer":{"spanish":"Admiro las ciudades donde las plazas, que suelen ser abiertas y accesibles, permiten que ni\xf1os, mayores y visitantes compartan el mismo entorno.","english":"I admire cities where public squares, which are usually open and accessible, allow children, older people, and visitors to share the same environment."}},{"question":{"spanish":"Presenta una propuesta que te parezca viable.","english":"Present a proposal that seems workable to you."},"answer":{"spanish":"La propuesta que me parece m\xe1s viable es ampliar el transporte nocturno, dado que muchas personas terminan de trabajar cuando ya no hay conexiones seguras.","english":"The proposal that seems most workable to me is expanding late-night transport, given that many people finish work when there are no longer safe connections."}},{"question":{"spanish":"Explica qu\xe9 hace una buena mediadora.","english":"Explain what makes a good mediator."},"answer":{"spanish":"Una buena mediadora es quien escucha a todas las partes, hace distinciones claras y busca un lenguaje que reduzca la tensi\xf3n sin ocultar el conflicto.","english":"A good mediator is someone who listens to all sides, makes clear distinctions, and looks for language that reduces tension without hiding the conflict."}},{"question":{"spanish":"Describe la empresa para la cual te gustar\xeda trabajar.","english":"Describe the company you would like to work for."},"answer":{"spanish":"Me gustar\xeda trabajar para una empresa cuyo objetivo principal fuera \xfatil socialmente y cuya cultura premiara la reflexi\xf3n, no solo la velocidad.","english":"I would like to work for a company whose main objective is socially useful and whose culture rewards reflection, not just speed."}},{"question":{"spanish":"Contrasta dos soluciones para un mismo problema.","english":"Contrast two solutions to the same problem."},"answer":{"spanish":"Una soluci\xf3n puede parecer barata a corto plazo; sin embargo, otra m\xe1s costosa quiz\xe1 resulte mejor si evita da\xf1os futuros y genera confianza.","english":"One solution may seem cheap in the short term; however, another that is more expensive may prove better if it prevents future harm and builds trust."}},{"question":{"spanish":"Describe un detalle que parece accesorio pero importa.","english":"Describe a detail that seems secondary but matters."},"answer":{"spanish":"Un detalle accesorio que a veces importa mucho es el tono del mensaje, porque puede abrir un di\xe1logo o cerrarlo antes de que empiece.","english":"A secondary detail that sometimes matters a lot is the tone of a message, because it can open a dialogue or shut it down before it even begins."}},{"question":{"spanish":"Habla de un proyecto cuyo objetivo apoyas.","english":"Talk about a project whose goal you support."},"answer":{"spanish":"Apoyo un proyecto cuyo objetivo es recuperar solares vac\xedos para crear huertos urbanos, lo cual fortalecer\xeda la vida comunitaria.","english":"I support a project whose goal is to reclaim empty lots to create urban gardens, which would strengthen community life."}},{"question":{"spanish":"Menciona un lugar donde piensas mejor.","english":"Mention a place where you think more clearly."},"answer":{"spanish":"Pienso mejor en un caf\xe9 tranquilo donde puedo observar a la gente sin interrupciones y ordenar las ideas que todav\xeda no est\xe1n claras.","english":"I think more clearly in a quiet caf\xe9 where I can observe people without interruptions and organize the ideas that are not yet clear."}},{"question":{"spanish":"Explica qu\xe9 te convence en un discurso.","english":"Explain what persuades you in a speech."},"answer":{"spanish":"Me convence un discurso que reconoce objeciones razonables y que, adem\xe1s, conecta los datos con experiencias humanas concretas.","english":"I am persuaded by a speech that acknowledges reasonable objections and also connects data with concrete human experiences."}},{"question":{"spanish":"Di por qu\xe9 los contraargumentos pueden mejorar una tesis.","english":"Say why counterarguments can improve a thesis."},"answer":{"spanish":"Los contraargumentos pueden mejorar una tesis porque obligan a precisar los l\xedmites de la idea principal y muestran que el an\xe1lisis no es superficial.","english":"Counterarguments can improve a thesis because they force you to clarify the limits of the main idea and show that the analysis is not superficial."}},{"question":{"spanish":"Describe a una vecina cuya idea ayud\xf3 a la comunidad.","english":"Describe a neighbor whose idea helped the community."},"answer":{"spanish":"Una vecina cuya idea transform\xf3 el barrio propuso abrir el patio de la escuela los fines de semana para actividades que reunieran a familias y mayores.","english":"A neighbor whose idea transformed the neighborhood proposed opening the school courtyard on weekends for activities that would bring together families and older residents."}},{"question":{"spanish":"Habla de una decisi\xf3n que, aunque dif\xedcil, fue correcta.","english":"Talk about a decision that, although difficult, was the right one."},"answer":{"spanish":"Aunque fue dif\xedcil, rechazar una oferta apresurada fue lo correcto, porque la propuesta que parec\xeda brillante ocultaba condiciones poco claras.","english":"Although it was difficult, turning down a rushed offer was the right choice, because the proposal that looked brilliant concealed unclear conditions."}},{"question":{"spanish":"Resume una discusi\xf3n y la conclusi\xf3n a la que llegaron.","english":"Summarize a discussion and the conclusion you reached."},"answer":{"spanish":"Discutimos sobre ampliar horarios de biblioteca y, por lo tanto, llegamos a una conclusi\xf3n intermedia que atend\xeda tanto al presupuesto como a la necesidad estudiantil.","english":"We discussed extending library hours and therefore reached a middle-ground conclusion that addressed both the budget and student needs."}}]}}}')}}]);